import java.util.*;

public class App {
    public static void main(String[] args) {
        String[] names = {"Aisha", "Raj", "Priya", "Vikram", "Anita"};
        String[] depts = {"Engineering", "Sales", "Engineering", "HR", "Sales"};

        Map<String, List<String>> byDept = new HashMap<>();
        for (int i = 0; i < names.length; i++) {
            byDept.computeIfAbsent(depts[i], k -> new ArrayList<>()).add(names[i]);
        }

        // Sort for output
        List<String> sortedDepts = new ArrayList<>(byDept.keySet());
        Collections.sort(sortedDepts);
        for (String dept : sortedDepts) {
            List<String> members = byDept.get(dept);
            Collections.sort(members);
            System.out.println(dept + ": " + members);
        }
    }
}

