        Map<String, TreeSet<String>> tagIndex = new TreeMap<>();  // sorted tags

        // Helper to index an article
        addToIndex(tagIndex, "Java Guide",   new String[]{"java", "programming"});
        addToIndex(tagIndex, "Python Intro", new String[]{"python", "programming"});
        addToIndex(tagIndex, "OOP Concepts", new String[]{"java", "oop", "programming"});

