import java.util.*;

public class App {
    public static void main(String[] args) {
        // Structure 1: SKU → price
        Map<String, Double> priceBysku = new HashMap<>();
        // Structure 2: category → Set of SKUs
        Map<String, TreeSet<String>> byCategory = new HashMap<>();
        // Structure 3: price → SKU (sorted by price)
        TreeMap<Double, String> byPrice = new TreeMap<>();

        // Add products: (sku, category, price)
        String[][] products = {
            {"SKU-001", "Electronics", "799.0"},
            {"SKU-002", "Electronics", "1999.0"},
            {"SKU-003", "Electronics", "18999.0"},
            {"SKU-004", "Accessories", "499.0"}
        };

        for (String[] p : products) {
            String sku = p[0], cat = p[1];
            double price = Double.parseDouble(p[2]);
            priceBysku.put(sku, price);
            byCategory.computeIfAbsent(cat, k -> new TreeSet<>()).add(sku);
            byPrice.put(price, sku);
        }

        System.out.println("Price of SKU-003: " + priceBysku.get("SKU-003"));
        System.out.println("Electronics SKUs: " + byCategory.get("Electronics"));

        StringBuilder sb = new StringBuilder("Cheapest first: ");
        for (Map.Entry<Double, String> e : byPrice.entrySet()) {
            sb.append(e.getValue()).append("(").append(e.getKey()).append(") ");
        }
        System.out.println(sb.toString().trim());
    }
