import java.util.*;

class Employee {
    String id, name, dept;
    Employee(String id, String name, String dept) {
        this.id = id; this.name = name; this.dept = dept;
    }
    public String toString() { return name + " (" + dept + ")"; }
}

class EmployeeSystem {
    Map<String, Employee> byId = new HashMap<>();   // O(1) lookup
    Set<String> processedIds = new HashSet<>();     // O(1) membership

    void add(Employee e) { byId.put(e.id, e); }

    Employee find(String id) { return byId.get(id); }  // O(1)

    void markProcessed(String id) { processedIds.add(id); }  // auto-dedup

    boolean isProcessed(String id) { return processedIds.contains(id); }  // O(1)
}

public class App {
    public static void main(String[] args) {
        EmployeeSystem sys = new EmployeeSystem();
        sys.add(new Employee("E001", "Aisha", "Engineering"));
        sys.add(new Employee("E002", "Raj", "Sales"));

        System.out.println("Found: " + sys.find("E001"));
        sys.markProcessed("E001");
        System.out.println("Processed: " + sys.isProcessed("E001"));
    }
}

import java.util.*;

class Patient {
    String id, name, ward;
    Patient(String id, String name, String ward) {
        this.id = id; this.name = name; this.ward = ward;
    }
    public String toString() { return name + " (" + ward + ")"; }
}

public class App {
    public static void main(String[] args) {
        // 1. Instant lookup by ID
        Map<String, Patient> byId = new HashMap<>();
        // 2. Admission order
        List<String> admissionOrder = new ArrayList<>();
        // 3. Ward → sorted patient names
        Map<String, TreeSet<String>> byWard = new HashMap<>();
        // 4. Discharged IDs
        Set<String> discharged = new HashSet<>();
        // 5. Active ward names
        Set<String> activeWards = new HashSet<>();

        // Add patients
        Patient[] patients = {
            new Patient("P001", "Aisha",  "Surgical"),
            new Patient("P002", "Raj",    "Medical"),
            new Patient("P003", "Priya",  "Surgical"),
            new Patient("P004", "Vikram", "ICU")
        };
        for (Patient p : patients) {
            byId.put(p.id, p);
            admissionOrder.add(p.id);
            byWard.computeIfAbsent(p.ward, k -> new TreeSet<>()).add(p.name);
            activeWards.add(p.ward);
        }

        // Discharge P002
        discharged.add("P002");

        System.out.println("Patient P001: " + byId.get("P001"));
        System.out.println("Today's admissions: " + admissionOrder);
        System.out.println("Surgical ward: " + byWard.get("Surgical"));
        System.out.println("P002 discharged: " + discharged.contains("P002"));
        System.out.println("Active wards: " + activeWards.size());
    }
}

import java.util.*;

class Product {
    String sku, name, category;
    double price;
    boolean inStock;
    Product(String sku, String name, String cat, double price, boolean inStock) {
        this.sku=sku; this.name=name; this.category=cat; this.price=price; this.inStock=inStock;
    }
    public String toString() { return name; }
}

class ECommerceEngine {
    List<Product> catalog = new ArrayList<>();
    Map<String, Product> bySku = new HashMap<>();
    Map<String, List<Product>> byCategory = new HashMap<>();
    Set<String> outOfStock = new HashSet<>();
    TreeMap<Double, List<Product>> byPrice = new TreeMap<>();

    void addProduct(Product p) {
        catalog.add(p);
        bySku.put(p.sku, p);
        byCategory.computeIfAbsent(p.category, k -> new ArrayList<>()).add(p);
        byPrice.computeIfAbsent(p.price, k -> new ArrayList<>()).add(p);
        if (!p.inStock) outOfStock.add(p.sku);
    }

    List<Product> search(String query) {
        List<Product> results = new ArrayList<>();
        for (Product p : catalog) {
            if (p.name.toLowerCase().contains(query.toLowerCase())) results.add(p);
        }
        return results;
    }

    List<Product> inPriceRange(double min, double max) {
        List<Product> results = new ArrayList<>();
        for (List<Product> prods : byPrice.subMap(min, true, max, true).values()) {
            results.addAll(prods);
        }
        return results;
    }
}

public class App {
    public static void main(String[] args) {
        ECommerceEngine engine = new ECommerceEngine();
        engine.addProduct(new Product("SKU-001", "Mouse",    "Electronics", 799,   true));
        engine.addProduct(new Product("SKU-002", "Keyboard",  "Electronics", 1999,  true));
        engine.addProduct(new Product("SKU-003", "Monitor",   "Electronics", 18999, false));
        engine.addProduct(new Product("SKU-004", "Java Book", "Books",        649,   true));

        System.out.println("Total products: " + engine.catalog.size());
        System.out.println("Search 'key': " + engine.search("key"));
        System.out.println("In range ₹500-₹2000: " + engine.inPriceRange(500, 2000));
        System.out.println("Electronics count: " + engine.byCategory.get("Electronics").size());
        System.out.println("Out of stock: " + engine.outOfStock.size());
    }
}
